import pytest
import yaml
import os
from pathlib import Path
import sys

# Add parent directory to path so we can import algorithm modules
sys.path.insert(0, str(Path(__file__).parent.parent))

from graph import Graph, create_graph


def _load_fixture(filename):
    """Load a YAML fixture file."""
    fixture_path = Path(__file__).parent / "fixtures" / filename
    with open(fixture_path, "r") as f:
        return yaml.safe_load(f)


def _build_graph_from_fixture(fixture_data):
    """Build a Graph object from fixture data."""
    return create_graph(fixture_data["edges"], is_directed=True)


@pytest.fixture(params=[
    "simple_graph.yaml",
    "grid_graph.yaml",
    "disconnected_graph.yaml",
])
def fixture_file(request):
    """Parametrized fixture that loads each YAML fixture."""
    return request.param


@pytest.fixture
def simple_graph_fixture():
    """Load the simple weighted graph fixture."""
    return _load_fixture("simple_graph.yaml")


@pytest.fixture
def grid_graph_fixture():
    """Load the 3x3 grid graph fixture."""
    return _load_fixture("grid_graph.yaml")


@pytest.fixture
def disconnected_graph_fixture():
    """Load the disconnected graph fixture."""
    return _load_fixture("disconnected_graph.yaml")


def manhattan_simple(vertex):
    """Manhattan distance heuristic for simple graph nodes labeled a-e."""
    # Simple heuristic: alphabet distance to 'e'
    element = vertex.element()
    if isinstance(element, str):
        return abs(ord('e') - ord(element))
    return 0


def manhattan_grid(vertex):
    """Manhattan distance heuristic for grid-based coordinates."""
    element = vertex.element()
    if isinstance(element, tuple) and len(element) == 2:
        x, y = element
        goal_x, goal_y = 2, 2
        return abs(x - goal_x) + abs(y - goal_y)
    return 0


def zero_heuristic(vertex):
    """Zero heuristic (effectively Dijkstra's algorithm)."""
    return 0


@pytest.fixture
def heuristics():
    """Provide a mapping of heuristic names to functions."""
    return {
        "manhattan_simple": manhattan_simple,
        "manhattan_grid": manhattan_grid,
        "zero_heuristic": zero_heuristic,
    }

