def manhattan_grid(vertex):
    """Manhattan distance heuristic for grid-based coordinates."""
    element = vertex.element()
    if isinstance(element, str) and element.startswith('('):
        # Parse string representation like "(0,0)"
        try:
            coords = element.strip('()').split(',')
            x, y = int(coords[0]), int(coords[1])
            goal_x, goal_y = 2, 2
            return abs(x - goal_x) + abs(y - goal_y)
        except (ValueError, IndexError):
            pass
    return 0

